def send_gmail_alert(recipient, patient_name, patient_id, alerts):
    timestamp = datetime.datetime.now().strftime("%d %b %Y, %I:%M %p")
    rows_html = ""
    for a in alerts:
        is_crit = a["level"] == "CRITICAL"
        bc = "#dc2626" if is_crit else "#c2410c"
        bb = "#fef2f2" if is_crit else "#fff7ed"
        be = "#fca5a5" if is_crit else "#fdba74"
        rows_html += f"""<tr>
          <td style="padding:10px 14px;border-bottom:1px solid #f3f4f6;font-size:14px;color:#111827;font-weight:600;">{a['vital']}</td>
          <td style="padding:10px 14px;border-bottom:1px solid #f3f4f6;font-size:14px;color:#dc2626;font-weight:700;">{a['value']}</td>
          <td style="padding:10px 14px;border-bottom:1px solid #f3f4f6;">
            <span style="background:{bb};color:{bc};border:1px solid {be};padding:3px 8px;border-radius:4px;font-size:12px;font-weight:700;">{a['level']}</span>
          </td>
          <td style="padding:10px 14px;border-bottom:1px solid #f3f4f6;font-size:13px;color:#6b7280;">{a['message']}</td>
        </tr>"""
    html_email = f"""<!DOCTYPE html><html><body style="margin:0;padding:0;background:#f3f4f6;font-family:Arial,sans-serif;">
<div style="max-width:660px;margin:32px auto;background:#fff;border:1px solid #e5e7eb;border-radius:12px;overflow:hidden;">
  <div style="height:5px;background:linear-gradient(90deg,#dc2626,#ef4444,#f97316);"></div>
  <div style="background:#fef2f2;padding:24px 32px;border-bottom:1px solid #fecaca;">
    <div style="font-size:11px;color:#9ca3af;letter-spacing:.12em;text-transform:uppercase;margin-bottom:6px;">HealNet AI · Automated Alert</div>
    <div style="font-size:22px;font-weight:800;color:#dc2626;">🚨 Critical Vitals Detected</div>
  </div>
  <div style="padding:20px 32px;border-bottom:1px solid #f3f4f6;">
    <table style="width:100%;border-collapse:collapse;font-size:13px;">
      <tr><td style="padding:5px 0;width:110px;color:#9ca3af;font-size:11px;font-weight:700;text-transform:uppercase;">Patient</td><td style="color:#111827;font-weight:700;font-size:15px;">{patient_name}</td></tr>
      <tr><td style="padding:5px 0;color:#9ca3af;font-size:11px;font-weight:700;text-transform:uppercase;">Patient ID</td><td style="color:#dc2626;font-weight:700;">{patient_id}</td></tr>
      <tr><td style="padding:5px 0;color:#9ca3af;font-size:11px;font-weight:700;text-transform:uppercase;">Alert Time</td><td style="color:#374151;">{timestamp}</td></tr>
    </table>
  </div>
  <div style="padding:24px 32px;">
    <div style="font-size:11px;color:#dc2626;text-transform:uppercase;letter-spacing:.12em;font-weight:700;margin-bottom:14px;">⚠ Flagged Vitals</div>
    <table style="width:100%;border-collapse:collapse;border:1px solid #e5e7eb;">
      <thead><tr style="background:#f9fafb;">
        <th style="padding:10px 14px;text-align:left;color:#6b7280;font-size:11px;text-transform:uppercase;font-weight:700;border-bottom:1px solid #e5e7eb;">Vital</th>
        <th style="padding:10px 14px;text-align:left;color:#6b7280;font-size:11px;text-transform:uppercase;font-weight:700;border-bottom:1px solid #e5e7eb;">Value</th>
        <th style="padding:10px 14px;text-align:left;color:#6b7280;font-size:11px;text-transform:uppercase;font-weight:700;border-bottom:1px solid #e5e7eb;">Status</th>
        <th style="padding:10px 14px;text-align:left;color:#6b7280;font-size:11px;text-transform:uppercase;font-weight:700;border-bottom:1px solid #e5e7eb;">Note</th>
      </tr></thead><tbody>{rows_html}</tbody>
    </table>
  </div>
  <div style="margin:0 32px 24px;background:#fef2f2;border:1px solid #fca5a5;border-radius:8px;padding:14px 18px;">
    <div style="color:#dc2626;font-size:14px;font-weight:700;">🏥 Please review <span style="color:#111827;">{patient_name}</span> immediately.</div>
  </div>
  <div style="padding:14px 32px;border-top:1px solid #f3f4f6;background:#f9fafb;font-size:11px;color:#9ca3af;">Automated alert · HealNet AI</div>
</div></body></html>"""
    try:
        msg = MIMEMultipart("alternative")
        msg["Subject"] = f"🚨 HealNet Alert — {patient_name} ({patient_id})"
        msg["From"]    = f"HealNet AI <{SENDER_EMAIL}>"
        msg["To"]      = recipient
        msg.attach(MIMEText(html_email, "html"))
        with smtplib.SMTP_SSL("smtp.gmail.com", 465) as srv:
            srv.login(SENDER_EMAIL, SENDER_PASSWORD)
            srv.sendmail(SENDER_EMAIL, recipient, msg.as_string())
        return True, ""
    except smtplib.SMTPAuthenticationError:
        return False, "Gmail auth failed."
    except Exception as e:
        return False, str(e)

def check_and_alert(patient_name, patient_id, vitals_map, recipient, cooldown=300):
    """
    Upgraded alert engine:
    - Categorises vitals into Critical / Warning / Normal
    - Sends email only for Critical/HIGH alerts (with cooldown)
    - Logs every alert cycle to st.session_state["alert_log"]
    Returns: (critical_alerts, warning_alerts)
    """
    now_dt    = datetime.datetime.now()
    timestamp = now_dt.strftime("%d %b %Y, %I:%M:%S %p")
    raw_ts    = now_dt.strftime("%Y%m%d%H%M%S")

    critical_alerts, warning_alerts = [], []
    for n, (v, l, m) in vitals_map.items():
        if l in ("CRITICAL", "HIGH"):
            critical_alerts.append({"vital": n, "value": v, "level": l, "message": m, "category": "Critical"})
        elif l in ("MODERATE", "LOW"):
            warning_alerts.append({"vital": n, "value": v, "level": l, "message": m, "category": "Warning"})

    # ── Email (Critical only, with cooldown) ──────────────────────────
    email_sent, email_error = False, ""
    key_cd, key_ok, key_err = (
        f"last_alert_{patient_id}",
        f"alert_ok_{patient_id}",
        f"alert_err_{patient_id}",
    )
    if critical_alerts and recipient and (time.time() - st.session_state.get(key_cd, 0) > cooldown):
        ok, err = send_gmail_alert(recipient, patient_name, patient_id, critical_alerts)
        st.session_state[key_cd] = time.time()
        email_sent, email_error  = ok, err
        if ok:
            st.session_state[key_ok] = True
            st.session_state.pop(key_err, None)
        else:
            st.session_state[key_err] = err
            st.session_state.pop(key_ok, None)

    # ── Log to alert history (de-duplicate on rapid re-runs) ─────────
    last_raw = st.session_state.get(f"last_log_ts_{patient_id}", "")
    all_new  = critical_alerts + warning_alerts
    if all_new and (not last_raw or (int(raw_ts) - int(last_raw)) >= 30):
        alert_log = st.session_state.get("alert_log", [])
        for a in all_new:
            alert_log.insert(0, {
                "raw_timestamp": raw_ts,
                "timestamp":     timestamp,
                "patient_id":    patient_id,
                "patient_name":  patient_name,
                "vital":         a["vital"],
                "value":         a["value"],
                "category":      a["category"],
                "level":         a["level"],
                "message":       a["message"],
                "email_sent":    email_sent if a["category"] == "Critical" else False,
                "email_error":   email_error if a["category"] == "Critical" else "",
                "acknowledged":  False,
                "ack_by":        "",
                "ack_time":      "",
            })
        st.session_state["alert_log"]              = alert_log[:300]
        st.session_state[f"last_log_ts_{patient_id}"] = raw_ts

    return critical_alerts, warning_alerts

