def breadcrumb(steps, current):
    parts = []
    for i, step in enumerate(steps):
        if step == current:
            parts.append(f'<span class="crumb-active">{step}</span>')
        elif steps.index(step) < steps.index(current):
            parts.append(f'<span style="color:#3d6080;">{step}</span>')
        else:
            parts.append(f'<span style="color:#2a4a60;">{step}</span>')
        if i < len(steps) - 1:
            parts.append('<span class="crumb-sep"> › </span>')
    st.html(f'<div class="breadcrumb">{"".join(parts)}</div>')

def sub_label(text):
    st.html(f'<div class="sub-label">{text}</div>')

def mh_pill(text, color="#00d4ff", bg="rgba(0,212,255,.1)"):
    """Render a small badge/tag."""
    if not text or not text.strip():
        return ""
    return f'<span style="display:inline-block;background:{bg};color:{color};border:1px solid {color};border-radius:4px;padding:2px 8px;font-size:.72rem;font-family:\'Share Tech Mono\',monospace;margin:2px;">{text.strip()}</span>'

def comma_pills(text, color="#00d4ff", bg="rgba(0,212,255,.1)"):
    if not text:
        return "—"
    return " ".join(mh_pill(t, color, bg) for t in text.split(",") if t.strip())

